public static Map<String, Integer> countWords(List<String> words) {
    Map<String, Integer> counts = new HashMap<>();
    for (String word : words) {
        counts.put(word, counts.getOrDefault(word, 0) + 1);
    }
    return counts;
}

public static boolean isPalindrome(String s) {
    if (s == null) return false;
    String lower = s.toLowerCase();
    String reversed = new StringBuilder(lower).reverse().toString();
    return lower.equals(reversed);
}

public static List<String> findDuplicates(List<String> items) {
    Set<String> seen = new HashSet<>();
    Set<String> duplicates = new HashSet<>();
    for (String item : items) {
        if (!seen.add(item)) {
            duplicates.add(item);
        }
    }
    return new ArrayList<>(duplicates);
}

public static List<String> validateRequiredFields(Map<String, String> data, List<String> required) {
    List<String> invalid = new ArrayList<>();
    for (String field : required) {
        String value = data.get(field);
        if (value == null || value.isBlank()) {
            invalid.add(field);
        }
    }
    return invalid;
}

public static boolean waitForCondition(BooleanSupplier condition, long timeoutMs) {
    long start = System.currentTimeMillis();
    while (System.currentTimeMillis() - start < timeoutMs) {
        if (condition.getAsBoolean()) {
            return true;
        }
        try {
            Thread.sleep(500);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            return false;
        }
    }
    return condition.getAsBoolean();
}

