            result.add(row.get(key));
        }
    }
    return result;
}

import java.util.Objects;

public static Map<String, String> diffMaps(Map<String, Object> expected, Map<String, Object> actual) {
    Map<String, String> diffs = new LinkedHashMap<>();
    for (String key : expected.keySet()) {
        if (!actual.containsKey(key)) {
            diffs.put("MISSING: " + key, "expected '" + expected.get(key) + "', got nothing");
        } else if (!Objects.equals(expected.get(key), actual.get(key))) {
            diffs.put("MISMATCH: " + key, "expected '" + expected.get(key) + "', got '" + actual.get(key) + "'");
        }
    }
    for (String key : actual.keySet()) {
        if (!expected.containsKey(key)) {
            diffs.put("EXTRA: " + key, "not in expected");
        }
    }
    return diffs;
}

