import java.util.regex.Pattern;

public static String validatePattern(String fieldName, String value, String regex) {
    if (value == null) {
        return String.format("Field '%s' is null, cannot match pattern '%s'", fieldName, regex);
    }
    boolean matches = Pattern.compile(regex).matcher(value).matches();
    if (matches) {
        return null;
    }
    return String.format("Field '%s' value '%s' does not match pattern '%s'", fieldName, value, regex);
}

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.util.*;

public class JsonHelper {

    private static final ObjectMapper MAPPER = new ObjectMapper();

    public static Map<String, Object> parseJson(String json) {
        if (json == null || json.isBlank()) {
            return Collections.emptyMap();
        }
        try {
            return MAPPER.readValue(json, new TypeReference<Map<String, Object>>() {});
        } catch (JsonProcessingException e) {
            System.err.println("Failed to parse JSON: " + e.getOriginalMessage());
            return Collections.emptyMap();
        }
    }
}

import java.io.IOException;
import java.nio.file.*;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.List;

public static void appendResult(Path reportFile, String testName, String status) throws IOException {
    if (reportFile.getParent() != null) {
        Files.createDirectories(reportFile.getParent());
    }
    String timestamp = LocalDateTime.now()
            .format(DateTimeFormatter.ofPattern("yyyy-MM-dd'T'HH:mm:ss"));
    String line = String.format("%s [%s] %s%n", timestamp, status, testName);
    Files.write(reportFile, List.of(line),
            StandardOpenOption.CREATE,
            StandardOpenOption.APPEND);
}

import java.util.concurrent.atomic.AtomicInteger;

public class InvocationCounter {

    private final AtomicInteger count = new AtomicInteger(0);

    public void increment() {
        count.incrementAndGet();
    }

    public int getCount() {
        return count.get();
    }

    public void reset() {
        count.set(0);
    }

    // Demo
    public static void main(String[] args) throws InterruptedException {
        InvocationCounter counter = new InvocationCounter();
        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) counter.increment();
        });
        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) counter.increment();
        });
        t1.start(); t2.start();
        t1.join();  t2.join();
        System.out.println(counter.getCount()); // 2000
    }
}

import java.time.LocalDate;

public static boolean isWithinLastDays(String dateStr, int days) {
    LocalDate date = LocalDate.parse(dateStr);
    LocalDate today = LocalDate.now();
    LocalDate cutoff = today.minusDays(days);
    return !date.isBefore(cutoff) && !date.isAfter(today);
}

public class TestValidationException extends RuntimeException {

    private final String fieldName;
    private final Object expected;
    private final Object actual;

    public TestValidationException(String fieldName, Object expected, Object actual) {
        super(String.format(
            "Assertion failed for field '%s': expected '%s' but got '%s'",
            fieldName, expected, actual));
        this.fieldName = fieldName;
        this.expected = expected;
        this.actual = actual;
    }

    public TestValidationException(String fieldName, Object expected, Object actual, Throwable cause) {
        super(String.format(
            "Assertion failed for field '%s': expected '%s' but got '%s'",
            fieldName, expected, actual), cause);
        this.fieldName = fieldName;
        this.expected = expected;
        this.actual = actual;
    }

    public String getFieldName() { return fieldName; }
    public Object getExpected()  { return expected; }
    public Object getActual()    { return actual; }
}

