void apiResponse_shouldHaveAllExpectedFields(Map<String, Object> response) {
    SoftAssertions.assertSoftly(softly -> {
        softly.assertThat(response.get("status"))
              .as("status field")
              .isEqualTo("OK");

        softly.assertThat(response.get("code"))
              .as("code field")
              .isEqualTo(200);

        softly.assertThat(response.get("data"))
              .as("data field")
              .isNotNull();

        softly.assertThat(response.get("message").toString())
              .as("message field")
              .startsWith("Success");
